arguments.argument:
if global.gamePaused=false
{
  if atkProg=0
  {
    y-=runAcc/2
    atkTime+=1
    if atkTime>=8
    {
      if place_meeting(x,y-runAcc,oSolid)
      {
        if type=0 {bClockWise=1; currentDir=RIGHT}
        else {bClockWise=0; currentDir=LEFT}
        atkTime=0
        atkProg=1
      }
    }
  }
  else if atkProg=1
  {
    enemyFollowBorder()
    atkTime+=1
    if atkTime=150 {instance_destroy()}
  }
}
